//! Focused proof for default mesh probabilistic admission.
//!
//! This benchmark isolates the admission decision: baseline recomputes a small
//! deterministic route payload every request; probability mode observes the
//! same key distribution and reuses the cached payload once finite cover is
//! satisfied.

use std::hint::black_box;
use std::time::Instant;

use distributed_inference::mesh_probability_admission::{
    MeshProbabilityAdmission, MeshProbabilityDecision, MeshProbabilityPolicy,
};

fn read_usize_flag(name: &str, fallback: usize) -> usize {
    let prefix = format!("--{name}=");
    std::env::args()
        .find_map(|arg| arg.strip_prefix(&prefix).map(str::to_string))
        .and_then(|value| value.parse().ok())
        .filter(|value| *value > 0)
        .unwrap_or(fallback)
}

fn route_payload(path: &str) -> Vec<u8> {
    let mut state = 0xcbf29ce484222325_u64;
    for _ in 0..96 {
        for byte in path.as_bytes() {
            state ^= u64::from(*byte);
            state = state.wrapping_mul(0x100000001b3);
            state ^= state.rotate_left(17);
        }
    }
    format!("mesh:{path}:{state:016x}").into_bytes()
}

fn percentile(sorted: &[u128], numerator: usize, denominator: usize) -> u128 {
    if sorted.is_empty() {
        return 0;
    }
    let index = sorted
        .len()
        .saturating_mul(numerator)
        .checked_div(denominator)
        .unwrap_or(0)
        .min(sorted.len().saturating_sub(1));
    sorted[index]
}

fn summarize(samples: &[u128]) -> (u128, u128, u128, u128) {
    let mut sorted = samples.to_vec();
    sorted.sort_unstable();
    let mean = samples.iter().sum::<u128>() / samples.len().max(1) as u128;
    (
        mean,
        percentile(&sorted, 50, 100),
        percentile(&sorted, 95, 100),
        *sorted.last().unwrap_or(&0),
    )
}

fn main() {
    let iterations = read_usize_flag("iterations", 20_000);
    let hot_ratio = read_usize_flag("hot-ratio", 9).min(10);
    let hot_path = "/.aeon/fib20-rf?n=20&format=bwf2";
    let cold_path = "/.aeon/runtime-attestation";

    let mut baseline = Vec::with_capacity(iterations);
    for index in 0..iterations {
        let path = if index % 10 < hot_ratio {
            hot_path
        } else {
            cold_path
        };
        let started = Instant::now();
        black_box(route_payload(path));
        baseline.push(started.elapsed().as_nanos());
    }

    let mut admission = MeshProbabilityAdmission::new(MeshProbabilityPolicy::default());
    let mut admitted = Vec::with_capacity(iterations);
    let mut reuse_count = 0usize;
    for index in 0..iterations {
        let path = if index % 10 < hot_ratio {
            hot_path
        } else {
            cold_path
        };
        let started = Instant::now();
        let witness = admission.observe(path);
        if let Some(payload) = admission.get_admitted_cached(&witness) {
            if matches!(
                witness.decision,
                MeshProbabilityDecision::Reuse | MeshProbabilityDecision::Speculate
            ) {
                reuse_count += 1;
            }
            black_box(payload);
            admitted.push(started.elapsed().as_nanos());
            continue;
        }
        let payload = route_payload(path);
        admission.remember(path, payload.clone());
        black_box(payload);
        admitted.push(started.elapsed().as_nanos());
    }

    let (base_mean, base_p50, base_p95, base_max) = summarize(&baseline);
    let (prob_mean, prob_p50, prob_p95, prob_max) = summarize(&admitted);
    let speedup = base_mean as f64 / prob_mean.max(1) as f64;
    println!("mesh probability admission bench");
    println!("iterations={iterations} hot_ratio={hot_ratio}/10 reuse_count={reuse_count}");
    println!(
        "baseline mean={}ns p50={}ns p95={}ns max={}ns",
        base_mean, base_p50, base_p95, base_max
    );
    println!(
        "probability mean={}ns p50={}ns p95={}ns max={}ns speedup={:.2}x",
        prob_mean, prob_p50, prob_p95, prob_max, speedup
    );
}
